-- 0009_reference_data_from_filter_files.sql
-- Loads the 4 filter/reference files Master O supplied on 2026-04-24:
--   - Top 100 Commercial Carriers (parent + children) → carriers
--   - Top Clusters (105) → affiliations (type=cluster)
--   - Insurance Journal Top 100 P/C Agencies (2025) → top_agency_lists + top_agency_members (100)
--   - Top Regional Retailers (101 across 8 regions) → top_agency_lists + top_agency_members
-- Ignored: Wholesalers_MGA.xlsx (uploaded by mistake).

-- Extend top_agency_members with a region column so the Regional Retailers list
-- can group members by geography (Top 100 list leaves it NULL).
ALTER TABLE public.top_agency_members
  ADD COLUMN IF NOT EXISTS region text;

-- ============ CARRIERS (Top 100 parent groups + 301 children) ============
-- For each parent, insert a row with name=parent, group_name=parent (so it shows up
-- in its own group). Then insert each child with group_name = parent.

-- ============ CLUSTERS → affiliations (type='cluster') ============

-- ============ TOP AGENCY LISTS + MEMBERS ============
-- Create both lists first (with deterministic UUIDs so we can reference them).
-- List A: Insurance Journal Top 100 (2025)
-- List B: Top Regional Retailers
