  VALUES (
    'Insurance Journal Top 100 Property/Casualty Agencies (2025)',
    2025,
    '21st annual ranking of independent P/C agencies by Insurance Journal. Ranked by P/C revenue.'
  )
  RETURNING id
),
list_b AS (
  VALUES (
    'Top Regional Retailers by Geography',
    NULL,
    'Regional commercial P/C retail agencies grouped by US geographic region. Not rank-ordered.'
  )
  RETURNING id
),
